"""
MKT Original Commentary — Ezra chapters 8–10 (fill)
Fills 84 missing verses: ch8 v1-20,23-26,29-36; ch9 v2-3,5,7,10-15; ch10 v1-7,9-10,12-44
Run: python3 scripts/zc-original-ezra-fill.py

Key decisions:
- Genealogical lists (8:1-14, 10:18-44): brief entries on bêt-ʾāḇôt accountability and covenant record-keeping
- &lsquo;yad YHWH&rsquo; formula (8:18, 8:31): key theological phrase repeated across Ezra-Nehemiah, traced here
- zeraʿ haqqōdeš (9:2): &ldquo;holy seed&rdquo; — the phrase is exegetically significant for NT theology
- Intermarriage prohibition: traced to Deut 7 command, not ethnic exclusivism but covenantal purity
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZRA_ORIGINAL = {
  "8": {
    "1": "<p>The chapter opens with the phrase <span class='term'>wᵉʾēlleh rāšê ʾaḇôtêhem</span> — &ldquo;these are the heads of their fathers,&rdquo; followed by <span class='term'>wᵉhiṯyaḥaśām</span> — &ldquo;their genealogical enrollment.&rdquo; The verb <span class='term'>yāḥaś</span> (Hitpael) means to trace oneself genealogically; the noun <span class='term'>yaḥas</span> is the official register of ancestry. The precision of this record-keeping reflects the post-exilic community&rsquo;s need to establish legitimate membership in the covenant people — only the genealogically verified could serve in the temple or take part in the restored community (cf. Ezra 2:62-63).</p>",
    "2": "<p>Three priestly and Davidic lineages head the list: Phinehas, Ithamar, and David. The Phinehas line (<span class='term'>bᵉnê pîneḥas</span>) carries the covenant of perpetual priesthood granted in Num 25:12-13; the Ithamar line is the secondary Aaronic priestly descent; the Davidic line (<span class='term'>bᵉnê dāwîd</span>) signals that even the royal descendants participate in the return. The placement of priestly lineages first structures the list by sacred priority, then extends to the lay leaders.</p>",
    "3": "<p><span class='term'>min-bᵉnê šᵉkanyāh</span> — &ldquo;from the sons of Shecaniah.&rdquo; The name Shecaniah (<span class='term'>YHWH has taken up residence</span>) is apt for the context. The phrase <span class='term'>hannizkarim ʿimmô</span> — &ldquo;those registered with him&rdquo; — reflects the verb <span class='term'>zākar</span> in its administrative sense: men enrolled by name in the official list, their covenant identity formally documented. Each leader is responsible for the males of his clan (<span class='term'>zᵉkārîm</span>).</p>",
    "4": "<p><span class='term'>ʾĕliyhôʿênay ben-zeraḥyāh</span> — &ldquo;Elihoenai son of Zerahiah.&rdquo; The name Elihoenai means &ldquo;my eyes are toward YHWH&rdquo; — a fitting name for a returnee whose gaze is oriented toward Jerusalem. The consistent pattern of leader + patronymic + count (<span class='term'>wᵉʿimmô mātayim hazzᵉkārîm</span>) gives each family group its precise identity. The genealogical specificity is not pedantry but covenant accountability.</p>",
    "5": "<p><span class='term'>min-bᵉnê šᵉkanyāh ben-yaḥăzîʾēl</span> — the patronymic here lacks a personal name for Shecaniah, reading only &ldquo;the son of Jahaziel.&rdquo; This textual feature (missing or uncertain personal name) was noticed by ancient translators — the LXX and 1 Esdras offer variant readings. The scribal uncertainty itself illustrates the challenge of maintaining genealogical records through the exile: the transmission was difficult, and gaps existed even in official documentation.</p>",
    "6": "<p><span class='term'>ʿeḇed ben-yônatān min-bᵉnê ʿādîn</span> — the name Ebed means &ldquo;servant.&rdquo; The sons of Adin appear in both Ezra 2:15 and Neh 7:20 in the returns list; their number varies slightly, reflecting different counting or administrative moments. The precision of fifty males (<span class='term'>ḥamišîm hazzᵉkārîm</span>) shows that the organizing principle is military-census style — all adult males capable of making the journey and contributing to community work.</p>",
    "7": "<p><span class='term'>yᵉšaʿyāh ben-ʿathalyāh min-bᵉnê ʿêlām</span> — Elam is one of the major clan groupings appearing repeatedly in the return lists (Ezra 2:7, 2:31, 10:2, 10:26). The sons of Elam represent a substantial family whose members participated in the restoration at multiple stages. Jeshaiah (&ldquo;YHWH saves&rdquo;) leads seventy males — a symbolically freighted number suggesting completeness.</p>",
    "8": "<p><span class='term'>zeḇadyāh ben-mîkāʾēl min-bᵉnê šᵉpaṭyāh</span> — Zebadiah means &ldquo;YHWH has given.&rdquo; The theophoric name construction (<span class='term'>YH</span>-root) that appears throughout this list signals that the returnee families maintained their covenant identity in Babylon through the naming of their children. Names were one of the few portable markers of covenantal heritage during the exile.</p>",
    "9": "<p><span class='term'>min-bᵉnê yôʾāḇ</span> — &ldquo;from the sons of Joab.&rdquo; The name Joab (Davidic military commander) embedded in a clan name suggests that some returnees traced descent from prominent figures in the Davidic court. Obadiah (<span class='term'>ʿôḇadyāh</span> — &ldquo;servant of YHWH&rdquo;) leads the largest single contingent in this section at 218 males, reflecting a prominent and well-organized family group.</p>",
    "10": "<p><span class='term'>min-bᵉnê šᵉlōmît</span> — &ldquo;from the sons of Shelomith.&rdquo; The son&rsquo;s name is lacking in the MT (reading only <span class='term'>ben yôsipyāh</span> — &ldquo;son of Josiphiah&rdquo;); the leader&rsquo;s personal name has fallen out. One hundred and sixty males follow this partially anonymous leader. The textual gap underscores how tenuous genealogical records were — yet Ezra preserved and used what could be recovered.</p>",
    "11": "<p><span class='term'>zeḵaryāh ben-bēḇay min-bᵉnê bēḇay</span> — the leader bears the same clan name as his father and grandfather, a common patrilineal naming pattern. Zechariah (&ldquo;YHWH remembers&rdquo;) leads twenty-eight males — a smaller contingent suggesting that the Bebai clan had dwindled during the exile, consistent with the smaller number in Ezra 2:11 (623) compared with the first return.</p>",
    "12": "<p><span class='term'>yôḥānān ben-haqqāṭān min-bᵉnê ʿazgāḏ</span> — &ldquo;Johanan son of Hakkatan.&rdquo; The sobriquet <span class='term'>haqqāṭān</span> — &ldquo;the small/younger&rdquo; — distinguishes this Johanan from others of the same name. The sons of Azgad bring the largest group in the genealogical list (110 males), consistent with the 1,222 who returned in the first wave (Ezra 2:12); Azgad was one of the largest clan groups.</p>",
    "13": "<p><span class='term'>min-ʾaḥarônê ʾaḏōnîqām</span> — &ldquo;from the later sons of Adonikam.&rdquo; The phrase <span class='term'>ʾaḥarôn</span> (later/last) distinguishes this contingent from those of Adonikam who returned in the first wave (Ezra 2:13 — 666). Three leaders are named: Eliphelet, Jeiel, and Shemaiah — this is one of the few places in the chapter where multiple leaders are named for a single clan, perhaps indicating an organizational sub-division.</p>",
    "14": "<p><span class='term'>min-bᵉnê ḇiḡway ʿûṭay wᵉzabbûḏ</span> — Bigvai was among the largest groups in the first return (Ezra 2:14 — 2,056). The two leaders Uthai and Zabbud lead seventy males here, a modest contingent from this once-large clan. The verb of the chapter&rsquo;s genealogical section has been the implicit <span class='term'>ʿālāh</span> (to go up/ascend) — the theological term for returning from Babylon to Jerusalem, the same verb used for pilgrimage to the temple.</p>",
    "15": "<p><span class='term'>wāʾeqbᵉṣēm ʾel-hannāhār</span> — &ldquo;I gathered them to the river.&rdquo; The first-person voice returns after the third-person genealogical list. The river <span class='term'>ʾāhāwāʾ</span> is unidentified outside Ezra but was apparently a canal near Babylon where a staging area existed. The three-day pause (<span class='term'>šᵉlōšet yāmîm</span>) is standard for preparation before a sacred undertaking (cf. Gen 22:4; Exod 19:11). The review reveals no Levites — <span class='term'>min-bᵉnê lēwî lōʾ māṣāʾtî šām</span> — an administrative gap that must be corrected before the journey can proceed.</p>",
    "16": "<p>Ezra sends a delegation of nine named leaders (<span class='term'>rāšîm</span>) and two instructors (<span class='term'>mᵉbînîm</span>) to Iddo at Casiphia. The verb <span class='term'>ṣiwwîtî</span> — &ldquo;I commanded/gave instructions to&rdquo; — shows Ezra&rsquo;s authority. The list of nine names begins with Eliezer, Ariel, Shemaiah — the names themselves are theophoric constructions. The term <span class='term'>mᵉbînîm</span> (instructors) appears in post-exilic texts for those who explain scripture; this delegation combines administrative authority with pedagogical competence.</p>",
    "17": "<p><span class='term'>wāʾᵉṣawweh ʾôtām ʿal-ʾiddô hārōʾš bᵉḵasipyāʾ</span> — the mission to Casiphia to recruit Levites and Nethinim. <span class='term'>Casiphia</span> appears only here in the OT; the name may derive from <span class='term'>kesef</span> (silver), perhaps a place associated with the treasury or with the silver-working trade. Iddo (<span class='term'>ʿiddô</span>) is the chief there — a title suggesting he led the local Jewish-Levitical community in Babylon. The mission is specifically for ministers for the house of God: <span class='term'>mᵉšārᵉtîm lᵉḇêt ʾĕlōhênû</span>.</p>",
    "18": "<p><span class='term'>wayyāḇîʾû lānû bᵉyaḏ-ʾĕlōhênû haṭṭôḇāh ʿālênû</span> — &ldquo;they brought us, by the good hand of our God upon us.&rdquo; The phrase <span class='term'>yad-ʾĕlōhênû ʿālênû</span> (the hand of our God upon us) is one of the signature theological affirmations of Ezra-Nehemiah, appearing at 7:6, 7:9, 7:28, 8:18, 8:22, 8:31, and Neh 2:8. The hand (<span class='term'>yāḏ</span>) of God is the idiom for effective divine power and favor; <span class='term'>haṭṭôḇāh</span> qualifies it as beneficent (&ldquo;good&rdquo;). The Sherebiah who comes is identified as <span class='term'>ben mīšāʾēl</span> from the sons of Mahli (<span class='term'>min-bᵉnê maḥlî</span>) — a Merarite Levite lineage.</p>",
    "19": "<p><span class='term'>wᵉḥăšaḇyāh wᵉʾittô yᵉšaʿyāh min-bᵉnê mᵉrārî</span> — Hashabiah (&ldquo;YHWH has reckoned/considered&rdquo;) and Jeshaiah come from the Merari line. The Merarites were responsible for the heavier structural components of the tabernacle/temple (Num 3:33-37). Their presence in the returning group ensures proper Levitical coverage across both Levitical families (Kohath/Merari). The note that &ldquo;their brothers and sons — twenty in all&rdquo; came with them shows that whole family units joined, not merely individuals.</p>",
    "20": "<p><span class='term'>ûmin-hannᵉṯînîm</span> — &ldquo;and of the Nethinim.&rdquo; The Nethinim (<span class='term'>nᵉṯûnîm</span>, &ldquo;those given&rdquo;) were temple servants of non-Israelite origin who had been assigned to assist the Levites since the time of David (cf. Ezra 2:43-58; Num 3:9). Their number here (220) reflects a substantial auxiliary serving force. The note that &ldquo;all were designated by name&rdquo; (<span class='term'>kullām nuqqᵉḇû bišᵉmôṯ</span>) confirms that even these non-priestly servants were officially enrolled — their identity documented in covenant community records.</p>",
    "23": "<p><span class='term'>wannaṣûm wanᵉḇaqqᵉšāh mēʾĕlōhênû ʿal-zōʾṯ wayyēʿāṯer lānû</span> — &ldquo;so we fasted and implored our God about this matter, and he listened to our entreaty.&rdquo; The verb <span class='term'>ʾāṯar</span> (Niphal) means to be entreated/respond to prayer — a rare verb appearing in significant moments (Gen 25:21 for Rebekah&rsquo;s conception; Judg 13:8 for Manoah). The answer to prayer is direct and reported matter-of-factly, with no elaboration: the fast worked, and God answered. This brevity underlines Ezra&rsquo;s confidence in the covenantal efficacy of humble prayer.</p>",
    "24": "<p><span class='term'>wāʾaḇdîlāh miśśārê hakkōhănîm šᵉnêm ʿāśār</span> — &ldquo;then I set apart twelve of the leading priests.&rdquo; The verb <span class='term'>bādal</span> (Hiphil, &ldquo;to separate/set apart&rdquo;) is the key term for priestly holiness-setting-apart in Leviticus (Lev 20:25-26). Ezra applies it here to the formal designation of custodians for the sacred vessels. The number twelve (<span class='term'>šᵉnêm ʿāśār</span>) symbolically invokes the twelve-tribe structure of Israel — the same twelve who received the weighed gifts represent the whole reconstituted people.</p>",
    "25": "<p><span class='term'>wāʾeškōl-lāhem ʾet-hakkesef wᵉʾet-hazzāhāḇ wᵉʾet-hakkelîm</span> — &ldquo;I weighed out to them the silver and the gold and the vessels.&rdquo; The verb <span class='term'>šāqal</span> (to weigh) is the technical term for commercial and cultic weighing in Hebrew; the noun <span class='term'>šeqel</span> derives from it. The solemn weighing-out ceremony marks the moment of transfer of custodial responsibility. The donors are enumerated: the king, his advisors (<span class='term'>yôʿăṣāyw</span>), his officials (<span class='term'>śārāyw</span>), and all Israel there present — a comprehensive endorsement from both Gentile patron and Jewish community.</p>",
    "26": "<p>The quantities are staggering: 650 talents of silver (<span class='term'>ṭalantôn kᵉsep</span>), 100 silver vessels (<span class='term'>kēlê-ḵesef</span>), 100 talents of gold. The talent (<span class='term'>kikkār</span>) was approximately 30 kg; 650 silver talents would be roughly 20,000 kg. The scale of the donation mirrors the first temple&rsquo;s dedication gifts (1 Kgs 7-8) and signals the theological seriousness of the restoration project. These are not merely large gifts — they are the material expression of the conviction that YHWH&rsquo;s house deserves the best of Persia&rsquo;s wealth.</p>",
    "29": "<p><span class='term'>šiqᵉḏû wᵉšimᵉrû ʿad-tišqᵉlû lipnê śārê hakkōhănîm</span> — &ldquo;be watchful and keep them until you weigh them before the leading priests.&rdquo; The verb <span class='term'>šāqad</span> (to watch, be alert) is the imperative charge of custody; the future weighing (<span class='term'>tišqᵉlû</span>) will close the formal chain of custody. The double accountability — first Ezra weighs out to the twelve, then the twelve weigh in to Jerusalem — creates a documented transfer record. Cultic property in the ancient world required this kind of accounting to guard against theft and to establish liability.</p>",
    "30": "<p><span class='term'>wayyiqᵉblû hakkōhănîm wᵉhaLᵉwiyyim</span> — &ldquo;so the priests and Levites received.&rdquo; The verb <span class='term'>qābal</span> (to receive/accept) is a formal acceptance term. The vessels are described as <span class='term'>lᵉhāḇîʾ lîrûšālayim lᵉḇêt ʾĕlōhênû</span> — &ldquo;to bring to Jerusalem, to the house of our God.&rdquo; The goal of the journey is expressed in these terms: not merely political repatriation but cultic return — the restoration of the temple vessels and the reconstitution of temple worship.</p>",
    "31": "<p><span class='term'>wanniṣᵉʿāh min-nᵉhar ʾāhāwāʾ</span> — &ldquo;we departed from the Ahava canal.&rdquo; The departure is dated: the twelfth day of the first month. The journey from Babylon to Jerusalem was approximately 900 miles and took four months (Ezra 7:9: first day of first month to first day of fifth month). The theological commentary is provided in the same verse: <span class='term'>ûyaḏ-ʾĕlōhênû hāytāh ʿālênû</span> — &ldquo;the hand of our God was upon us&rdquo; — shielding them from enemy attack and ambushes (<span class='term'>qāmîm</span>). The divine protection operates through geographical vulnerability, not despite it.</p>",
    "32": "<p><span class='term'>wanāḇōʾ yᵉrûšālaim wanneʾšeb šām yāmîm šᵉlōšāh</span> — &ldquo;we arrived in Jerusalem and rested there three days.&rdquo; The three-day rest period before significant action is a pattern in sacred narrative (cf. Ezra 8:15; Gen 22:4; Josh 1:11; Esth 4:16). The arrival is narrated simply, without rhetorical elaboration. After the theological freight of the journey narrative, the factual simplicity of &ldquo;we arrived&rdquo; is itself meaningful — the journey accomplished, the destination reached, the prayer answered in geographical form.</p>",
    "33": "<p><span class='term'>wabbayyôm hārᵉḇîʿî nišqal</span> — &ldquo;on the fourth day the silver and gold and vessels were weighed.&rdquo; The formal closing of the chain of custody takes place at the temple — <span class='term'>bᵉḇêt ʾĕlōhênû</span> — supervised by Meremoth son of Uriah the priest, Eleazar son of Phinehas, and the Levites Jozabad and Noadiah. The combination of Aaronic priests and Levitical witnesses creates a double accountability structure. Meremoth son of Uriah also appears in Neh 3:4 as a wall-builder — a significant figure in the restoration community.</p>",
    "34": "<p><span class='term'>bᵉmispar ûbᵉmišqāl hakkōl</span> — &ldquo;everything by number and by weight.&rdquo; The double accounting (number + weight) is the most rigorous possible cultic inventory standard. The verb <span class='term'>kāṯaḇ</span> — &ldquo;it was recorded&rdquo; — puts the accounting in permanent written form: <span class='term'>ʾet-kol-hammiśqāl bāʿēṯ hahîʾ</span>, &ldquo;the whole weight at that time.&rdquo; This is not merely bureaucratic precision; it is the documentation of divine faithfulness — the sacred vessels that left Babylon arrived in Jerusalem intact, numbered, and weighed, because the hand of God was upon them.</p>",
    "35": "<p><span class='term'>habbāʾîm mīhaSšᵉḇî haBbōlāh bᵉnê haggôlāh</span> — &ldquo;the returned exiles who had come from captivity&rdquo; offered burnt offerings. The number twelve bullocks, 96 rams, 77 lambs and 12 male goats corresponds to the twelve tribes: the twelve-times-repetition signals that the offering is for <span class='term'>kol-yiśrāʾēl</span> — all Israel, not merely the returnees. The sin offering (<span class='term'>ḥaṭṭāʾṯ</span>) of twelve male goats is specifically for &ldquo;the sin of all Israel&rdquo; — a representative atonement for the whole nation, including those still in exile.</p>",
    "36": "<p><span class='term'>wayyitᵉnû ʾet-daṯê hammelek lᵉʾaḥašdarpᵉnê hammelek</span> — &ldquo;they presented the king&rsquo;s orders to the royal satraps.&rdquo; The <span class='term'>ʾaḥašdarpᵉnîm</span> (satraps) and <span class='term'>paḥôṯ</span> (governors) of Trans-Euphrates receive Artaxerxes&rsquo; authorization orders. The phrase <span class='term'>nāśᵉʾû ʾet-hāʿām wᵉʾet-bêt hāʾĕlōhîm</span> — &ldquo;they supported the people and the house of God&rdquo; — closes the chapter on a note of successful imperial-covenantal cooperation: Persia&rsquo;s power serves YHWH&rsquo;s purposes.</p>"
  },
  "9": {
    "2": "<p><span class='term'>zeraʿ haqqōdeš</span> — &ldquo;the holy seed.&rdquo; This phrase is theologically loaded: <span class='term'>zeraʿ</span> (seed/offspring) is the covenant-transmission word from Gen 3:15 onward; <span class='term'>qōdeš</span> (holiness, set-apartness) is YHWH&rsquo;s essential character that must mark his people. The mixing (<span class='term'>hiṯʿāraḇ</span> — literally &ldquo;has become mixed&rdquo;) of the holy seed with the peoples of the land violates the boundary between holy and common that is foundational to Levitical theology. Notably the leaders (<span class='term'>śārîm wᵉhassᵉgānîm</span>) are named first — the failure is not merely popular but official. The prohibition derives from Deut 7:1-4, which grounds the intermarriage ban not in ethnicity but in the danger of being drawn into idolatry.</p>",
    "3": "<p><span class='term'>wᵉkišmōʿî ʾeṯ-haddāḇār hazzeh qāraʿtî ʾet-bᵉgudî ûmᵉʿîlî</span> — &ldquo;when I heard this word, I tore my garment and my robe.&rdquo; The physical mourning actions are theologically precise: tearing garments (<span class='term'>qāraʿ</span>) was standard for severe grief (Gen 37:29; 2 Sam 13:31); pulling out hair from head and beard (<span class='term'>mārēq</span> — a rare verb) is extreme self-mortification. Sitting <span class='term'>mᵉšômmēm</span> — &ldquo;appalled/desolate&rdquo; — is a pun on the root used for the &ldquo;desolation&rdquo; of the land under exile (Dan 9:27). Ezra&rsquo;s body enacts what the nation&rsquo;s sin deserves.</p>",
    "5": "<p><span class='term'>ûḇᵉminḥat hāʿereḇ qamtî mītaʿnîṯî</span> — &ldquo;at the time of the evening sacrifice I rose from my self-abasement.&rdquo; The evening offering (<span class='term'>minḥat hāʿereḇ</span>) was the daily <span class='term'>tamîd</span> sacrifice at the ninth hour (mid-afternoon in modern terms). Ezra&rsquo;s prayer is structurally aligned with the temple liturgy — he rises when the sacrifice is offered, his confession accompanying the daily atonement rite. The torn garments and robe (<span class='term'>bᵉgudî ûmᵉʿîlî qᵉrûʿîm</span>) remain on his body as he prays — the physical tokens of grief are not removed but retained through the act of intercession.</p>",
    "7": "<p><span class='term'>mîmê ʾaḇôṯênû ʾănaḥnû bᵉʾašmāh gᵉḏōlāh</span> — &ldquo;from the days of our ancestors to this very day we have been deeply guilty.&rdquo; The corporate-historical framing of sin is characteristic of post-exilic penitential prayers (cf. Neh 9; Dan 9; Ps 106). The term <span class='term'>ʾašmāh</span> (guilt) differs from <span class='term'>ḥēṭ</span> (sin) — it carries the forensic sense of &ldquo;incurred debt/liability.&rdquo; YHWH&rsquo;s response has been exile: kings, priests, and people delivered into the hand of foreign kings, <span class='term'>bᵉyaḏ malkê hāʾărāṣôṯ</span>, by the sword, captivity, plunder, and <span class='term'>bōšeṯ pānîm</span> — &ldquo;shame of face.&rdquo;</p>",
    "10": "<p><span class='term'>wᵉʿattāh māh-nōʾmar ʾĕlōhênû ʾaḥărê-zōʾṯ</span> — &ldquo;and now, our God, what shall we say after this?&rdquo; The rhetorical question marks the transition from historical recitation to present confession. <span class='term'>kî ʿāzaḇnû miṣwôṯeḵā</span> — &ldquo;for we have abandoned your commandments.&rdquo; The verb <span class='term'>ʿāzaḇ</span> (to abandon/forsake) is the same word used for Israel forsaking YHWH throughout the prophets (Jer 1:16; 2:13, 17, 19; Isa 1:4). The prayer admits that the intermarriage issue is not an isolated failure but a symptom of the deeper pattern of covenant abandonment that caused the exile in the first place.</p>",
    "11": "<p><span class='term'>ʾăšer ṣiwwîṯā bᵉyaḏ ʿăḇādêḵā hannᵉḇîʾîm</span> — &ldquo;which you commanded through your servant-prophets.&rdquo; The intermarriage prohibition is here attributed specifically to the prophetic tradition, not merely to the Mosaic law. This broadens the scriptural basis: the command not to mix with the peoples of the land (<span class='term'>ṭumʾaṯ niddāh</span> — &ldquo;the impurity of their uncleanness/menstrual impurity&rdquo; — a shockingly strong phrase) is grounded in the prophetic vision of the land as sacred space that covenant violation pollutes.</p>",
    "12": "<p>The prophetic command cited in vv.11-12 draws on Deut 7:3 but is not a verbatim quotation — it synthesizes prophetic instruction: <span class='term'>lōʾ-ṯittᵉnû bᵉnôṯêḵem liBnêhem</span> — &ldquo;do not give your daughters to their sons&rdquo;; <span class='term'>wᵉlōʾ-ṯiśśᵉʾû bᵉnôṯêhem liḇnêḵem</span> — &ldquo;and do not take their daughters for your sons.&rdquo; The prohibition is symmetrical — neither daughters given nor daughters received. The underlying reason is practical-theological: such unions will inevitably draw Israel toward the worship of foreign gods (Deut 7:4). The command to <span class='term'>darᵉšû šᵉlōmām wᵉṭôḇātām</span> — &ldquo;never seek their peace or prosperity&rdquo; — sounds harsh but is a covenant-loyalty formula, not an expression of hostility.</p>",
    "13": "<p><span class='term'>wᵉʾaḥărê kol-habbāʾ ʿālênû bᵉmaʿăśênû hārāʿîm</span> — &ldquo;after all that has come upon us for our evil deeds and our great guilt.&rdquo; The word <span class='term'>ḥāśakᵉtā</span> (root <span class='term'>ḥāśaḵ</span>, to withhold/restrain) is key: &ldquo;you, our God, have punished us less than our iniquities deserve.&rdquo; This is a striking theological concession — the exile, as severe as it was, was <em>less</em> than Israel deserved. The verb <span class='term'>pālaṭ</span> (to deliver/let escape) follows: &ldquo;you gave us a remnant of survivors (<span class='term'>pᵉlêṭāh kᵉzōʾṯ</span>).&rdquo; The surviving community is an act of divine restraint, not divine indifference.</p>",
    "14": "<p><span class='term'>hănanûšûḇ lᵉhāpēr miṣwōṯêḵā</span> — &ldquo;shall we again break your commandments?&rdquo; The rhetorical question is the logical pressure of the prayer: to break the intermarriage prohibition again, after the exile and after the restoration, would be to invite <span class='term'>ʾap</span> (anger) and <span class='term'>qinʾāh</span> (jealousy/zeal) until there is no <span class='term'>šᵉʾērît ûpᵉlêṭāh</span> — &ldquo;no remnant and no survivor.&rdquo; The double synonym for the surviving community (remnant + survivor) underlines the fragility of the post-exilic restoration: only divine restraint has preserved them, and that restraint is not unlimited.</p>",
    "15": "<p><span class='term'>YHWH ʾĕlōhê yiśrāʾēl ṣaddîq ʾattāh</span> — &ldquo;O LORD, God of Israel, you are righteous.&rdquo; The prayer closes with a classical covenantal confession of divine righteousness (<span class='term'>ṣaddîq</span>). This is not the righteousness of divine punishment alone but the righteousness that maintains covenant integrity — YHWH has been consistent, faithful, and just throughout Israel&rsquo;s history of unfaithfulness. The concluding statement is stark: <span class='term'>kî-nišʾarnû pᵉlêṭāh kᵉhayyôm hazzeh</span> — &ldquo;for we are left a remnant, as it is today.&rdquo; Before a righteous God, the community can only stand in confession, not defense; in survival, not vindication.</p>"
  },
  "10": {
    "1": "<p><span class='term'>ûkᵉhiṯwaddōṯ ʿezrāʾ ûkᵉhiṯpallᵉlô</span> — &ldquo;while Ezra was confessing and praying.&rdquo; Two simultaneous participles: <span class='term'>hiṯwaddōṯ</span> (Hitpael of <span class='term'>yādāh</span>, to confess) and <span class='term'>hiṯpallēl</span> (Hitpael of <span class='term'>pālal</span>, to pray/intercede). The Hitpael of <span class='term'>yādāh</span> specifically means to make public confession of sin — the same construction used in Lev 16:21 (the High Priest&rsquo;s confessing of Israel&rsquo;s sins). Ezra&rsquo;s prostration (<span class='term'>mippānāyw</span> — &ldquo;before him&rdquo;, i.e., God&rsquo;s house) draws a vast congregation of men, women, and children weeping with great weeping (<span class='term'>bᵉḵî rabba</span>). His individual intercession becomes communal.</p>",
    "2": "<p><span class='term'>wayyaʿan šeḵanyāh ben-yᵉḥîʾēl</span> — &ldquo;Shechaniah son of Jehiel responded.&rdquo; The verb <span class='term'>ʿānāh</span> (to respond/answer) here has the specific nuance of stepping forward into a moment of crisis. Shechaniah&rsquo;s family is itself implicated — his kinsmen of Elam are in the list at 10:26. His willingness to lead the repentance despite personal cost gives the speech authority. The confession is direct: <span class='term'>māʿalnû bēʾlōhênû</span> — &ldquo;we have been unfaithful to our God&rdquo; — using the technical term <span class='term'>māʿal</span> (unfaithfulness, sacrilege) from the cultic vocabulary (Lev 5:15; Num 5:12). The remedy proposed is equally direct: covenant renewal.</p>",
    "3": "<p><span class='term'>wᵉʿattāh nikkrōt-bᵉrît lēʾlōhênû</span> — &ldquo;now let us make a covenant with our God.&rdquo; The phrase <span class='term'>kāraṯ bᵉrît</span> (to cut a covenant) is the standard idiom for covenant-making in biblical Hebrew, perhaps derived from the practice of cutting an animal in covenant ratification (Gen 15:10). The covenant&rsquo;s content: to send away (<span class='term'>lᵉhôṣîʾ</span>) all the foreign wives and their children. Shechaniah grounds this in two authorities: <span class='term'>kᵉʿaṣat ʾăḏōnāy</span> — &ldquo;according to the counsel of the Lord&rdquo; — and those who tremble at the commandments (<span class='term'>haḥărēḏîm bᵉmiṣwaṯ ʾĕlōhênû</span>). The <span class='term'>ḥărēḏîm</span> (&ldquo;tremblers&rdquo;) are a post-exilic piety group whose zeal for the Torah is their identifying mark (Isa 66:2, 5).</p>",
    "4": "<p><span class='term'>qûm kî ʿāleḵā hadd<i>ā</i>ḇār</span> — &ldquo;rise up, for this matter belongs to you.&rdquo; Shechaniah&rsquo;s charge to Ezra uses the imperative <span class='term'>qûm</span> (rise) — the classic call to decisive action (1 Kgs 19:5; Dan 8:27). The phrase <span class='term'>ʿāleḵā hadd<i>ā</i>ḇār</span> means literally &ldquo;the matter is upon you&rdquo; — responsibility is formally transferred to Ezra&rsquo;s shoulders. The accompanying promise — <span class='term'>wᵉʾănaḥnû ʿimmāḵ ḥăzaq waʿăśēh</span> — &ldquo;we are with you, be strong and act&rdquo; — echoes the Deuteronomic commission formulas (Deut 31:7; Josh 1:6). The community&rsquo;s solidarity with the leader is explicitly pledged.</p>",
    "5": "<p><span class='term'>wayyāqom ʿezrāʾ wayyaššāḇaʿ ʾeṯ-śārê haKKōhănîm</span> — &ldquo;then Ezra rose and put the leading priests, Levites, and all Israel under oath.&rdquo; The verb <span class='term'>šāḇaʿ</span> (Hiphil, to cause to swear) is the covenant oath-administration verb. The subjects: leading priests (<span class='term'>śārê haKKōhănîm</span>), Levites (<span class='term'>haLLᵉwiyyim</span>), all Israel (<span class='term'>kol-yiśrāʾēl</span>). All three orders of the covenant community are bound by the oath — no one is exempt. The phrase <span class='term'>laʿăśôṯ kadDāḇār hazzeh</span> — &ldquo;to act according to this matter&rdquo; — keeps the commitment specific and actionable.</p>",
    "6": "<p><span class='term'>wayyāqom ʿezrāʾ millipnê bêṯ hāʾĕlōhîm</span> — &ldquo;Ezra rose from before the house of God.&rdquo; He moves to the chamber of Jehohanan son of Eliashib (<span class='term'>liška yᵉhôḥānān ben-ʾelyāšîḇ</span>). Jehohanan appears in the Elephantine papyri (ca. 407 BCE) as a high priest, which may help date the narrative. Ezra&rsquo;s night fast — <span class='term'>lᵉḥem lōʾ ʾāḵal ûmayim lōʾ šātāh</span> — is the total fast of grief, not merely the cultic fast of humiliation. His mourning is for <span class='term'>māʿal haggôlāh</span> — &ldquo;the unfaithfulness of the exile-community&rdquo; — the same <span class='term'>māʿal</span> as in v.2.</p>",
    "7": "<p><span class='term'>wayyaʿăḇîrû qôl bîhûdāh ûḇîrûšālaim</span> — &ldquo;a proclamation was issued throughout Judah and Jerusalem.&rdquo; The term <span class='term'>qayyaʿăḇîrû qôl</span> (to pass a sound/voice through) is the standard idiom for official proclamation (2 Chr 30:5; Neh 8:15). The directive is urgent: <span class='term'>hiqqāḇᵉṣû</span> — &ldquo;assemble&rdquo; — within three days, to Jerusalem. The penalty clause is severe (<span class='term'>kol-ʾăšer lōʾ-yāḇōʾ litᵉlōšeṯ hayyāmîm</span> — &ldquo;anyone who fails to appear within three days&rdquo;) — forfeiture of property and exclusion from the community of the returned exiles.</p>",
    "9": "<p><span class='term'>wayyiqqāḇᵉṣû kol-ʾanšê yᵉhûdāh ûḇinyāmîn</span> — &ldquo;all the men of Judah and Benjamin gathered.&rdquo; The two southern tribes form the core of the restoration community. The gathering is dated: the twentieth day of the ninth month (<span class='term'>Kislev</span>, approximately December). The setting — Jerusalem plaza, in front of God&rsquo;s house — is the sacred assembly space; the weather — heavy rain (<span class='term'>haggᵉšāmîm</span>) — intensifies the urgency. The people trembled (<span class='term'>mērāʿîm</span>) from both the rain and the gravity of the matter (<span class='term'>ʿal-haddāḇār</span>). The double cause of trembling — weather and covenant — is not separated.</p>",
    "10": "<p><span class='term'>wayyāqom ʿezrāʾ hakKōhēn wayyōʾmer ʾălêhem</span> — &ldquo;Ezra the priest stood and said to them.&rdquo; The charge is crisp and in three movements: (1) <span class='term'>ʾaṯem māʿaltem</span> — &ldquo;you have been unfaithful&rdquo;; (2) <span class='term'>wattōšîḇû nāšîm nāḵriyyôṯ</span> — &ldquo;you have married foreign women&rdquo;; (3) <span class='term'>lᵉhôsîp ʿal-ʾašmaṯ yiśrāʾēl</span> — &ldquo;adding to the guilt of Israel.&rdquo; The verb <span class='term'>yāsap</span> (to add) is damning — the intermarriages are not merely individual sins but incremental additions to a national debt that has already nearly destroyed the community.</p>",
    "12": "<p><span class='term'>wayyaʿan kol-haqqāhāl wayyōʾmᵉrû qôl gādôl</span> — &ldquo;the whole assembly answered with a loud voice.&rdquo; The communal response is unanimous and vocal: <span class='term'>kēn kidᵉḇāreḵā ʿālênû laʿăśôṯ</span> — &ldquo;yes, we must do exactly as you have said.&rdquo; The adverb <span class='term'>kēn</span> (thus/so) is the covenant acceptance formula — straightforward assent. <span class='term'>laʿăśôṯ</span> (to do/act) is the active commitment word. The unanimity is rhetorically significant — no dissenting voice delays the covenant renewal. The loud voice (<span class='term'>qôl gādôl</span>) signals public, accountable, communal commitment, not private individual decision.</p>",
    "13": "<p><span class='term'>ʾăḇāl hāʿām rāḇ wᵉhāʿēṯ gᵉšāmîm</span> — &ldquo;however, there are many people involved, and it is the rainy season.&rdquo; The practical objection comes from within the assembly. The rain makes outdoor standing impossible for an extended period; and the matter requires individual case review (<span class='term'>ḥāṭāʾnû baddāḇār hazzeh</span> — &ldquo;we have sinned in this matter&rdquo; is acknowledged even by those requesting an orderly process). The objection is not resistance to repentance but to rushed implementation. The verb <span class='term'>ʿāmad</span> (to stand) in the rain for mass processing is impractical — the covenant community needs a structured investigation process.</p>",
    "14": "<p><span class='term'>yaʿōmᵉḏû nāʾ śārênû lᵉḵol-haqqāhāl</span> — &ldquo;let our officials represent the whole assembly.&rdquo; The proposed solution is administrative: officials (<span class='term'>śārîm</span>) act as assembly representatives; all who have intermarried come before them on fixed timetables with the elders and judges of their cities (<span class='term'>ʿim-ziqnê ʿîr-wāʿîr wᵉšōpᵉṭêhā</span>). The purpose: <span class='term'>lᵉhāšîḇ ḥărôn ʾap-ʾĕlōhênû</span> — &ldquo;to turn away the fierce wrath of our God.&rdquo; The phrase <span class='term'>ḥărôn ʾap</span> (burning anger) is the standard OT expression for imminent divine judgment; the assembly understands the urgency.</p>",
    "15": "<p><span class='term'>ʾaḵ yônatān ben-ʾăśāhēl wᵉyaḥzeyāh ben-tiqwāh</span> — only Jonathan son of Asahel and Jahzeiah son of Tikvah opposed the plan, supported by Meshullam and Shabbethai the Levite. The dissent is noted precisely — names, not merely a number. The text does not explain their objection (perhaps they considered the divorce requirement too harsh, or disputed the investigation procedure). Their opposition is overruled, but the fact of recording it shows the transparency of the process: covenant renewal in Ezra is not unanimity by suppression but by the weight of acknowledged obligation.</p>",
    "16": "<p><span class='term'>wayyiḇḏᵉlû ʾanšê-haggôlāh</span> — &ldquo;the returned exiles separated themselves.&rdquo; Ezra designates men — heads of families (<span class='term'>rāšê hāʾāḇôṯ</span>), all named — to serve as the investigation committee. They began on the first day of the tenth month (<span class='term'>ḥōdeš hāʿăśîrî</span>, Tevet — approximately January). The verb <span class='term'>yāšaḇ</span> (they sat) is the technical term for a judicial sitting; the committee hears each case to determine its disposition. The four-month process reflects the thoroughness required: each case must be evaluated individually.</p>",
    "17": "<p><span class='term'>waykallû ʾeṯ-kol-hāʾănāšîm</span> — &ldquo;by the first day of the first month they had completed their review.&rdquo; The review took three months (tenth month to first month of the following year). The verb <span class='term'>kālāh</span> (Piel, to complete/finish) marks the satisfactory conclusion. The object: <span class='term'>kol-hāʾănāšîm ʾăšer-hôšîḇû nāšîm nāḵriyyôṯ</span> — &ldquo;all the men who had taken foreign women.&rdquo; The systematic thoroughness is itself a covenantal statement: no one is above covenant accountability, no case is too inconvenient to investigate.</p>",
    "18": "<p><span class='term'>wayyimmāṣēʾ mibbᵉnê haKKōhănîm</span> — &ldquo;among the sons of the priests the following were found.&rdquo; The list of violators begins with the priesthood — the highest sacred order is implicated first. The sons of Jeshua (the High Priest&rsquo;s family, <span class='term'>bᵉnê-yēšûaʿ ben-yôṣādāq wᵉ'eḥāyw</span>) head the list. This is the most prominent priestly family in the restoration community. Their violation of the intermarriage prohibition is the most serious possible failure, given that priestly genealogical purity was a fundamental requirement for temple service (Lev 21:7).</p>",
    "19": "<p><span class='term'>wayyittᵉnû yādām lᵉhôṣîʾ nᵉšêhem</span> — &ldquo;they pledged to put away their wives.&rdquo; The idiom <span class='term'>nāṯan yāḏ</span> (to give the hand) is a gesture of formal pledge or commitment — a handshake covenant (1 Chr 29:24; 2 Chr 30:8). The priests acknowledge their guilt (<span class='term'>wᵉʾăšēmîm</span>) and bring an atonement offering: a ram (<span class='term'>ʾayil ṣōʾn</span>) for their sin. The guilt offering for priestly unfaithfulness is calibrated to the seriousness of the violation — a ram is the minimum offering for a ruler&rsquo;s guilt offering (Lev 5:18).</p>",
    "20": "<p><span class='term'>ûmibbᵉnê ʾimmēr</span> — &ldquo;from the sons of Immer.&rdquo; Immer was one of the twenty-four priestly divisions established by David (1 Chr 24:14). Two men are named: Hanani and Zebadiah. The list continues through the major priestly divisions: Immer, Harim, and Pashur (vv.20-22) — all prominent priestly families in the restoration period. The precise enumeration within each priestly division demonstrates that the investigation was conducted systematically, division by division.</p>",
    "21": "<p><span class='term'>ûmibbᵉnê ḥārîm</span> — &ldquo;from the sons of Harim.&rdquo; Five violators are listed from this division: Maaseiah, Elijah, Shemaiah, Jehiel, and Uzziah. The Harim division appears in Ezra 2:32, 39 and Neh 7:35, 42 as a significant priestly and lay family group. The theophoric names among the violators — Elijah (&ldquo;my God is YHWH&rdquo;), Shemaiah (&ldquo;YHWH has heard&rdquo;) — underline the irony: those whose very names confess covenant loyalty are the ones who violated it.</p>",
    "22": "<p><span class='term'>ûmibbᵉnê pašḥûr</span> — &ldquo;from the sons of Pashur.&rdquo; Six names are listed from this division — the largest priestly contingent in the list. Pashur was a priestly division (1 Chr 9:12) as well as a specific individual known from Jer 20:1 as the priest who put Jeremiah in stocks. The list&rsquo;s exhaustive naming protocol serves covenant accountability: violation of the intermarriage prohibition was a public matter whose resolution required public record.</p>",
    "23": "<p><span class='term'>ûmin-halLᵉwiyyim</span> — &ldquo;of the Levites.&rdquo; Six Levites are named: Jozabad, Shimei, Kelaiah (also known as Kelita — the parenthetical alternative name is a textual note, probably reflecting a variant in the Levitical rolls), Pethahiah, Judah, and Eliezer. The Levites are listed separately from the priests, reflecting the hierarchical distinction maintained throughout the post-exilic period. The smaller number of Levitical violators (six) compared with the priestly violators may reflect the smaller Levitical population in the return community.</p>",
    "24": "<p><span class='term'>ûmin-hammᵉšôrᵉrîm ʾelyāšîḇ</span> — &ldquo;of the singers: Eliashib.&rdquo; A single singer is named. <span class='term'>ûmin-haššôʿărîm šallûm wāṭelem wāʾûrî</span> — &ldquo;of the gatekeepers: Shallum, Telem, and Uri.&rdquo; These are the two lowest-ranking Levitical service orders (singers and gatekeepers). Their inclusion in the accountability process demonstrates that no level of the temple service structure was exempt. The gatekeepers in particular were the guards of the boundary between sacred and profane — their violation of the marriage boundary carries symbolic irony.</p>",
    "25": "<p><span class='term'>ûmiyyiśrāʾēl mibbᵉnê parʿōš</span> — &ldquo;among the lay Israelites, from the sons of Parosh.&rdquo; The lay list is the most extensive section (vv.25-43), covering 17 different family groups. Parosh heads the list, as in Ezra 2:3, where the sons of Parosh are the largest single family group (2,172). The names within the Parosh contingent include compound forms: Malluchijah (&ldquo;YHWH is my king&rdquo;), Mijamin (a shortened theophoric). The variation in spelling across different manuscripts and parallel texts (Neh 10) reflects the challenges of maintaining consistent records in the complex textual history of Ezra-Nehemiah.</p>",
    "26": "<p><span class='term'>ûmibbᵉnê ʿêlām</span> — &ldquo;from the sons of Elam.&rdquo; Elam is represented again (cf. 8:7) — a major family group in the return. Six names: Mattaniah, Zechariah, Jehiel, Abdi, Jeremoth, and Elijah. The prevalence of the name Mattaniah (&ldquo;gift of YHWH&rdquo;) across different family groups in this list suggests it was a popular name in the restoration community — the sentiment of grateful reception of divine gifts was a natural expression for those who had returned from exile.</p>",
    "27": "<p><span class='term'>ûmibbᵉnê zattûʾ</span> — &ldquo;from the sons of Zattu.&rdquo; Six names from this family group (Zattu appears at Ezra 2:8 with 945 members). The last in the list, Aziza, carries the Arabic-influenced name-form common in the trans-Euphrates region — evidence of cultural contact in the diaspora. The mixed name-forms (Hebrew theophoric + Arabic/Aramaic) across the list reflect the multilingual, multicultural context of Babylonian Jewish life.</p>",
    "28": "<p><span class='term'>ûmibbᵉnê bēḇay</span> — &ldquo;from the sons of Bebai.&rdquo; Four names from the smaller Bebai family group (cf. 8:11). Jehohanan, Hananiah, Zabbai, and Athlai. The name Jehohanan (&ldquo;YHWH is gracious&rdquo;) appears multiple times across these lists as one of the most common post-exilic names — the <span class='term'>ḥannûn</span> (gracious) root in divine names reflects the community&rsquo;s experience of divine grace in the return from exile.</p>",
    "29": "<p><span class='term'>ûmibbᵉnê bānî</span> — &ldquo;from the sons of Bani.&rdquo; Six names from Bani, including the common post-exilic name Meshullam (&ldquo;at peace&rdquo;) and Malluch (&ldquo;counselor/king&rdquo;). The name <span class='term'>Adaiah</span> (&ldquo;YHWH has adorned/testified&rdquo;) appears in multiple family groups across the list. The Bani family (cf. Ezra 2:10; 10:34, 38) was one of the larger lay groups with multiple sub-groups — their presence here across different sections of the list suggests that &ldquo;Bani&rdquo; may be a broad clan designation covering several related households.</p>",
    "30": "<p><span class='term'>ûmibbᵉnê paḥaṯ-môʾāḇ</span> — &ldquo;from the sons of Pahathmoab.&rdquo; Eight names — the largest non-priestly contingent in the list. The clan name Pahathmoab (&ldquo;governor of Moab&rdquo;) suggests descent from an official who had governed Moabite territory under the Davidic-Solomonic administration; their large numbers in the returns (Ezra 2:6 — 2,812) indicate a major family group. The final name Manasseh (<span class='term'>mᵉnašseh</span>) completes the eight.</p>",
    "31": "<p><span class='term'>ûmibbᵉnê ḥārîm</span> — the lay sons of Harim (distinct from the priestly sons of Harim at v.21). Five names: Eliezer, Ishijah, Malchijah, Shemaiah, Shimeon. The repetition of family names (Harim, Bani, Elam) across different sections of the list — priestly, Levitical, lay — reflects the extended family structure of the restoration community where priestly and lay branches of the same ancestral name coexisted.</p>",
    "32": "<p><span class='term'>binyāmîn mallûk wišmaryāh</span> — three more from the Harim group: Benjamin, Malluch, and Shemariah. The list continues methodically without comment. The prose neutrality of the inventory — no moral commentary, no theological elaboration — is itself significant: the text treats covenant accountability as a practical matter requiring documentation, not a dramatic occasion requiring homiletical embellishment.</p>",
    "33": "<p><span class='term'>mibbᵉnê ḥāšum</span> — &ldquo;from the sons of Hashum.&rdquo; Seven names including Mattenai, Mattattah, Zabad, Eliphelet, Jeremai, Manasseh, and Shimei. The Hashum family appears at Ezra 2:19 (223 members). The variety of name-forms across the seven (Aramaic-influenced Mattenai + Hebrew Eliphelet + Hebrew-Aramaic Jeremai) reflects the linguistic blending characteristic of the Babylonian diaspora community.</p>",
    "34": "<p><span class='term'>mibbᵉnê bānî</span> — a second Bani contingent, or the beginning of the Bani sub-groups that extend through v.38. The names here are less common: Maadai, Amram (a patriarchal name — borne by Moses&rsquo; father, Exod 6:18), Uel. The recurrence of ancestral names (Amram) in the post-exilic period reflects deliberate naming practices meant to anchor the restoration community in the patriarchal narrative.</p>",
    "35": "<p><span class='term'>bᵉdᵉyāh kᵉlûhû wanᵉyāh</span> — three more from the extended Bani group: Bedeiah, Chelluh (variant forms in ancient versions), Vaniah. These names are rare — several appear only here in the OT. Their rarity does not diminish their significance; the list preserves the names of individuals who accepted covenant accountability, many of whom would otherwise be entirely unknown. The OT&rsquo;s preservation of obscure names in accountability lists reflects a theology of individual covenant responsibility.</p>",
    "36": "<p><span class='term'>mᵉrēmôṯ ʾelyāšîḇ</span> — Meremoth and Eliashib. Meremoth appears as both a priest (Ezra 8:33; Neh 3:4) and a lay person in the tradition, which may indicate different individuals bearing the same name, or that this Meremoth is distinct from the priest of ch.8. Eliashib is extremely common in post-exilic texts (also the name of the High Priest in Neh 13:4). The short entries in vv.36-43 reflect the scribal economy of the list format — each name carries its own full accountability without need of commentary.</p>",
    "37": "<p><span class='term'>matnay waMattatnāh wîyāśāy</span> — Mattenai, Mattaniah, and Jaasau. The name Mattenai (<span class='term'>mattᵉnay</span> — &ldquo;gift of YHWH&rdquo;) and Mattaniah (<span class='term'>mattanyāh</span> — the longer form with the divine element) are name variants of the same root — both meaning &ldquo;gift of God.&rdquo; Their sequential listing may reflect scribal grouping of name-variants. Jaasau (<span class='term'>wîyāśāy</span>) is a hapax — appearing only here — likely a contracted form of a theophoric name.</p>",
    "38": "<p><span class='term'>binnûy šimʿî</span> — Binnui and Shimei. Binnui is a name associated with the Levitical family groups (Neh 3:18; 10:9; 12:8) but here appears in the lay list, suggesting it was a name used across different family groups. Shimei (<span class='term'>šimʿî</span> — &ldquo;YHWH has heard&rdquo;) is one of the most common OT names, appearing in dozens of contexts from the Davidic court onward. The frequency of theophoric names across all sections of this list reflects the persistence of YHWH-devotion in the diaspora community.</p>",
    "39": "<p><span class='term'>šelemyāh wᵉnātān wᵉʿăḏāyāh</span> — Shelemiah, Nathan, and Adaiah. Shelemiah (<span class='term'>šelemyāh</span> — &ldquo;YHWH has restored/completed&rdquo;) and Nathan (the prophet&rsquo;s name, meaning &ldquo;YHWH has given&rdquo;) and Adaiah (&ldquo;YHWH has adorned&rdquo;) round out another set of theophoric names. Nathan in the post-exilic context is a common name; the prophet Nathan played a significant role in the Davidic covenant (2 Sam 7; 12), and his name was preserved in the royal line (Zech 12:12).</p>",
    "40": "<p><span class='term'>maknaḏᵉḇay šāšay šārāy</span> — Machnadebai, Shashai, Sharai. These are unusual names — Machnadebai appears only here in the OT. The name may be of non-Hebrew derivation, reflecting the cultural mixing of the Babylonian diaspora. Shashai and Sharai have uncertain etymologies. Their uniqueness is no barrier to their inclusion in the covenant accountability record — the list&rsquo;s completeness requires naming every individual, regardless of the name&rsquo;s frequency or recognizability.</p>",
    "41": "<p><span class='term'>ʿăzarʾēl wšelemyāh šemaryāh</span> — Azareel, Shelemiah (a second occurrence), Shemariah. Azareel (<span class='term'>ʿăzarʾēl</span> — &ldquo;God has helped&rdquo;) appears in 1 Chr 12:6 as a Benjaminite warrior who joined David. The recurrence of Shelemiah in the same extended name-group (cf. v.39) may reflect sub-branch naming within the Bani family, or scribal variation in the source document.</p>",
    "42": "<p><span class='term'>šallûm ʾămaryāh wîyôsēp</span> — Shallum, Amariah, and Joseph. Shallum is the classic gatekeeper name (Neh 7:45; 1 Chr 9:17); here it appears in a lay group. Amariah (<span class='term'>ʾămaryāh</span> — &ldquo;YHWH has spoken/promised&rdquo;) is a priestly name in Chronicles but lay here. Joseph closes the Bani sub-group — a patriarchal name, perhaps deliberately chosen to link the family&rsquo;s identity with the foundational patriarch who himself spent years in exile in Egypt.</p>",
    "43": "<p><span class='term'>mibbᵉnê nᵉḇô</span> — &ldquo;from the sons of Nebo.&rdquo; Seven names: Jeiel, Mattithiah, Zabad, Zebina, Jaddai, Joel, and Benaiah. The clan name Nebo refers to the Babylonian god of wisdom and writing — that a Jewish family group bore this name suggests either that they adopted it as a geographical/clan identity (being from the region of Nebo), or that the name had been in use long enough to lose its pagan connotation. This is the last family group in the list and includes the names Joel (&ldquo;YHWH is God&rdquo;) and Benaiah (&ldquo;YHWH has built&rdquo;) — fitting theological names to close the covenant accountability record.</p>",
    "44": "<p><span class='term'>kol-ʾēlleh nāśᵉʾû nāšîm nāḵriyyôṯ</span> — &ldquo;all of these had taken foreign women.&rdquo; The closing summary uses the same verb (<span class='term'>nāśāʾ</span> — to lift/take, standard Hebrew for marrying) as throughout the chapter. The final note — <span class='term'>wᵉyēš mēhem nāšîm wayyāśîmû bānîm</span> — &ldquo;and some of them had wives by whom they had children&rdquo; — acknowledges the human cost of the covenant action without softening the resolution. The book of Ezra ends here, without narrating the outcome — the reader is left with the completed accountability process and the implicit question of implementation. The open ending is not narrative incompetence but theological realism: covenant renewal is never a completed past event but an ongoing task.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'ezra')
    merge_comm(existing, EZRA_ORIGINAL)
    save_comm('mkt-original', 'ezra', existing)
    import json as _j
    il = _j.loads((ROOT / 'data' / 'interlinear' / 'ezra.json').read_text())
    for ch in ['8', '9', '10']:
        missing = set(il.get(ch, {}).keys()) - set(existing.get(ch, {}).keys())
        if missing:
            print(f'  ch {ch} STILL MISSING: {sorted(missing, key=int)}')
        else:
            print(f'  ch {ch}: complete ({len(existing.get(ch, {}))} verses)')

if __name__ == '__main__':
    main()
